class MyPromise {
  constructor(executor) {
    this.state = 'pending';
    this.value = undefined;
    this.callbacks = [];
    const resolve = (val) => {
      if (this.state !== 'pending') return;
      this.state = 'fulfilled';
      this.value = val;
      this.callbacks.forEach(cb => cb.onFulfilled(val));
    };
    const reject = (reason) => {
      if (this.state !== 'pending') return;
      this.state = 'rejected';
      this.value = reason;
      this.callbacks.forEach(cb => cb.onRejected(reason));
    };
    try { executor(resolve, reject); } catch (e) { reject(e); }
  }
  then(onFulfilled, onRejected) {
    return new MyPromise((resolve, reject) => {
      const handle = () => {
        try {
          if (this.state === 'fulfilled') resolve(onFulfilled ? onFulfilled(this.value) : this.value);
          else if (this.state === 'rejected') onRejected ? resolve(onRejected(this.value)) : reject(this.value);
        } catch(e) { reject(e); }
      };
      if (this.state === 'pending') this.callbacks.push({ onFulfilled: () => handle(), onRejected: () => handle() });
      else queueMicrotask(handle);
    });
  }
  catch(onRejected) { return this.then(null, onRejected); }
}

function curry(fn) {
  return function curried(...args) {
    if (args.length >= fn.length) return fn.apply(this, args);
    return function(...args2) {
      return curried.apply(this, args.concat(args2));
    };
  };
}

